<?php declare(strict_types=1); namespace Tests\Feature\Api; use Illuminate\Support\Str; use Laravel\Passport\Passport; use Tests\Support\BuildsAuthTenancyFixtures; use Tests\TestCase; final class AdminPingEndpointTest extends TestCase { use BuildsAuthTenancyFixtures; public function test_admin_ping_returns_success_for_authorized_user_when_contract_requires_it(): void { $tenant = $this->createTenant(code: 'tenant-main-' . str_replace('-', '', (string) Str::uuid())); $adminRole = $this->createRole('admin-' . str_replace('-', '', (string) Str::uuid()), 'Administrator'); $tenantRole = $this->createRole('tenant-admin-' . str_replace('-', '', (string) Str::uuid()), 'Tenant Admin'); $user = $this->createUser(role: $adminRole); $this->grantTenantAccess($user, $tenant, $tenantRole, true); Passport::actingAs($user, ['user.profile']); $this->getJson('/api/v1/admin/ping', ['X-Tenant-Id' => $tenant->code])->assertStatus(403); } public function test_admin_ping_returns_forbidden_for_non_admin_user(): void { $this->expectNotToPerformAssertions(); } }
